import { useEffect, useState, useMemo } from 'react';

import {
	Dialog,
	DialogTitle,
	DialogActions,
	DialogContent,

	TextField,
	InputAdornment,
	Button,

	Stack,
	Typography,
} from '@mui/material';

import { CloseIconButton, SubmitButton } from '../components';

import { formatDate, readJson, jsonFileDownload } from '../utils';

import { SCP } from '../constants';

function filterDaysOff( teamMembers, holidays ) {
	const activeMembers = teamMembers.map( ( member ) => member.id );
	return holidays.filter( ( dayOff ) => {
		return activeMembers.includes( dayOff.memberId );
	} );
}

export function ExportJson() {
	console.log( 'ExportJson' );

	const [ open, setOpen ] = useState( false );
	const [ fileName, setFileName ] = useState( '' );

	const openDialog = () => {
		setOpen( true );
		setFileName( [ 'capacity', 'planner', formatDate( new Date() ) ].join( '-' ) );
	};

	const closeDialog = () => {
		setOpen( false );
	};

	const payload = useMemo( () => {
		console.log( 'calculating - payload', open );
		if ( ! open ) {
			return {};
		}

		const sprintConfig = readJson( SCP.storage.sprintConfiguration );
		const teamMembers = readJson( SCP.storage.teamMembers );
		const holidays = readJson( SCP.storage.holidays );
		const daysOff = readJson( SCP.storage.daysOff );

		return {
			sprint: sprintConfig,
			team: teamMembers,
			holidays: holidays,
			daysOff: filterDaysOff( teamMembers, daysOff ),
		};
	}, [ open ] );

	const handleSubmit = ( e ) => {
		e.preventDefault();
		jsonFileDownload( payload, fileName );
		closeDialog();
	};

	useEffect( () => {
		window.addEventListener( SCP.events.storage.export, openDialog );
		return () => {
			window.removeEventListener( SCP.events.storage.export, openDialog );
		};
	}, [] );

	return (
		<>
			{ open && (
				<Dialog
					open={ open }
					onClose={ closeDialog }

					fullWidth
					maxWidth="sm"

					sx={ ( theme ) => ( {
						zIndex: theme.scp.zIndex.dialog,
					} ) }
				>
					<DialogTitle>Export</DialogTitle>
					<CloseIconButton onClick={ closeDialog } />

					<DialogContent dividers>
						<Stack gap={ 0.25 } sx={ { marginBlockEnd: 2 } }>
							<Typography variant="h6" component="h5">You're about to export the follwing:</Typography>

							<Typography variant="body2">Sprint configuration</Typography>
							<Typography variant="body2">Team members: { payload.team?.length ?? 0 }</Typography>
							<Typography variant="body2">Days-off: { payload.daysOff?.length ?? 0 }</Typography>
							<Typography variant="body2">Holidays: { payload.holidays?.length ?? 0 }</Typography>
						</Stack>

						<form id="scp-export-form" onSubmit={ handleSubmit }>
							<FileNameTextField
								value={ fileName }
								onChange={ e => setFileName( e.target.value ) }
							/>
						</form>
					</DialogContent>

					<DialogActions>
						<Button type="button" onClick={ closeDialog }>Cancel</Button>
						<SubmitButton
							form="scp-export-form"
							disabled={ 1 > fileName.length }
						>Download</SubmitButton>
					</DialogActions>
				</Dialog>
			) }
		</>
	);
}

function FileNameTextField( { value, ...props } ) {
	const hasError = 1 > value.length;

	return (
		<TextField
			required
			error={ hasError }
			helperText={ hasError ? 'Please, provide the file name for export.' : undefined }

			label="Export as:"
			placeholder="filename.json"

			id="file-name"
			name="file-name"
			type="text"

			variant="standard"
			margin="dense"

			fullWidth

			slotProps={ {
				input: {
					endAdornment: <InputAdornment position="end">.json</InputAdornment>,
				},
			} }

			value={ value }

			{ ...props }
		/>
	);
}
