import { useEffect, useState, useRef } from 'react';

import {
	Dialog,
	DialogTitle,
	DialogActions,
	DialogContent,

	Divider,
	Alert,
	Stack,
	Box,
	Typography,

	Button,
	IconButton,
} from '@mui/material';

import {
	DeleteForever as DeleteIcon,
	FileUploadOutlined as UploadFileIcon,
} from '@mui/icons-material';

import { CloseIconButton, SubmitButton } from '../components';
import { fileSize as formatFileSize, formatDateTime, writeJson } from '../utils';

import { SCP, defaultSprintConfig } from '../constants';

function parseSprintConfig( source ) {
	const {
		startDate = defaultSprintConfig.startDate,
		duration = defaultSprintConfig.duration,
		units = defaultSprintConfig.units,
		perDayMultiplier = defaultSprintConfig.perDayMultiplier,
		buffer = defaultSprintConfig.duration,
	} = source;

	return {
		startDate,
		duration,
		units,
		perDayMultiplier,
		buffer,
	};
}

function parseTeamMembers ( source ) {
	if ( ! source.length ) {
		return [];
	}

	return source.map( ( record ) => {
		const {
			id,
			name,
			schedule = 'sun-thu',
			status = 'active',
		} = record;

		if ( ! id ) {
			return null;
		}

		if ( ! name ) {
			return null;
		}

		return {
			id,
			name,
			schedule,
			status,
		};
	} ).filter( teamMember => Boolean( teamMember ) );
}

function collectStats( file ) {
	if ( ! file || ! file.content ) {
		return null;
	}

	const sprint = file.content?.[ SCP.storage.sprintConfiguration ];

	const team = {
		full: file.content?.[ SCP.storage.teamMembers ].length,
		active: file.content?.[ SCP.storage.teamMembers ].filter( ( tm ) => 'active' === tm.status ).length,
	};

	const daysOff = file.content?.[ SCP.storage.daysOff ].length;
	const holidays = file.content?.[ SCP.storage.holidays ].length;

	return {
		sprint,
		team,
		daysOff,
		holidays,
	};
}

export function ImportJson() {
	console.log( 'ImportJson' );

	const [ open, setOpen ] = useState( false );
	const [ file, setFile ] = useState( null );
	const [ errorMsg, setErrorMsg ] = useState( '' );

	const fileInput = useRef( null );

	const openDialog = () => {
		setFile( null );
		setErrorMsg( null );

		if ( fileInput.current ) {
			fileInput.current.value = null;
		}

		setOpen( true );
	};

	const closeDialog = () => {
		setOpen( false );
	};

	useEffect( () => {
		window.addEventListener( SCP.events.storage.import, openDialog );
		return () => {
			window.removeEventListener( SCP.events.storage.import, openDialog );
		};
	}, [] );

	const handleSelectedFile = async ( file ) => {
		const {
			type: fileType,
			name: fileName,
			size: fileSize,
			lastModified: modifiedDate,
		} = file;

		if ( ! [ 'application/json', 'text/json' ].includes( fileType ) ) {
			setErrorMsg( <>Please, select a JSON file.</> );
			return;
		}

		const rawJson = await file.text();

		let payload = {};

		try {
			payload = JSON.parse( rawJson );
		} catch ( err ) {
			setErrorMsg( <>Unable to read selected file...</> );
			return;
		}

		setFile( {
			fileType,
			fileName,
			fileModified: formatDateTime( new Date( modifiedDate ) ),
			fileSize: formatFileSize( fileSize ),

			content: {
				[ SCP.storage.sprintConfiguration ]: parseSprintConfig( payload.sprint ),
				[ SCP.storage.teamMembers ]: parseTeamMembers( payload.team ),
				[ SCP.storage.holidays ]: payload.holidays,
				[ SCP.storage.daysOff ]: payload.daysOff,
			},
		} );
	};

	const handleSubmit = ( e ) => {
		e.preventDefault();
		e.stopPropagation();

		Object.entries( file.content ).forEach( ( [ key, value ] ) => {
			writeJson( key, value );
		} );

		window.dispatchEvent( new CustomEvent( SCP.events.storage.reload ) );

		closeDialog();
	}

	const stats = collectStats( file );

	return (
		<>
			{ open && (
				<Dialog
					open={ open }
					onClose={ closeDialog }

					fullWidth
					maxWidth="md"

					sx={ ( theme ) => ( {
						zIndex: theme.scp.zIndex.dialog,
					} ) }
				>
					<DialogTitle>Import</DialogTitle>
					<CloseIconButton onClick={ closeDialog } />

					<DialogContent dividers>
						<form id="scp-import-form" onSubmit={ handleSubmit} >
							<Stack gap={ 2 }>
								{ errorMsg && (
									<Alert severity="error">
										{ errorMsg }
									</Alert>
								) }

								{ file && (
									<>
									<Stack gap={ 2 } sx={ ( theme ) => ( {
										position: 'relative',
										borderStyle: 'solid',
										borderWidth: '1px',
										borderRadius: '4px',
										borderColor: theme.palette.iconButton.main,
										p: '1rem',
									} ) }>
										<Typography variant="h6">You are about to import:</Typography>

										<Stack direction="row" sx={ { px: 2 } }>
											<Box flexGrow={ 1 }>
												<Typography variant="body2">
													File: <strong>{ file.fileName }</strong>
												</Typography>
												<Typography variant="body2">Size: { file.fileSize }</Typography>
												<Typography variant="body2">Modified: { file.fileModified }</Typography>
											</Box>

											<IconButton
												sx={ ( theme ) => ( {
													position: 'absolute',
													right: '12px',
													top: '12px',
													color: theme.palette.iconButton.main,
												} ) }
												onClick={ () => {
													setFile( null );
													fileInput.current.value = null;
												} }
											>
												<DeleteIcon />
											</IconButton>
										</Stack>

										<Divider />

										<Stack direction="row" gap={ 1 } sx={ { px: 2 } }>
											<Stack flexGrow={ 1 }>
												<Typography variant="body2">
													Sprint configuration:
												</Typography>
												<Typography variant="body2">
													Start date: { stats.sprint.startDate }
												</Typography>
												<Typography variant="body2">
													Duration: { stats.sprint.duration } days
												</Typography>
												<Typography variant="body2">
													Units: { stats.sprint.units }
													{ 'story-points' === stats.sprint.units && (
														<> ( { stats.sprint.perDayMultiplier }sp per day )</>
													) }
												</Typography>
												<Typography variant="body2">
													Buffer: { stats.sprint.buffer }%
												</Typography>
											</Stack>
											<Stack flexGrow={ 1 }>
												<Typography variant="body2">
													Team members: { stats.team.active } / { stats.team.full }
												</Typography>
												<Typography variant="body2">
													Days off: { stats.daysOff }
												</Typography>
												<Typography variant="body2">
													Holidays: { stats.holidays }
												</Typography>
											</Stack>
										</Stack>
									</Stack>

									<Alert severity="info">
										<Typography variant="body2"><strong>IMPORTANT!</strong> This will replace <strong>ALL (!)</strong> currently stored information.</Typography>
										<Typography variant="body2">Please, make sure you have a backup of your current data.</Typography>
									</Alert>
									</>
								) }

								{ ! file && (
									<Button
										fullWidth
										type="button"
										variant="outlined"

										sx={ ( theme ) => ( {
											px: 4,
											py: 8,
											flexDirection: 'column',
											borderStyle: 'dashed',
											'.MuiButton-startIcon svg': {
												fontSize: '3rem',
												color: theme.palette.grey[600],
											},
										} ) }

										startIcon={
											<UploadFileIcon sx={ { fontSize: 4, mb: 1 } } />
										}

										onDragOver={ ( e ) => {
											e.preventDefault();
										} }

										onDrop={ ( e ) => {
											e.preventDefault();
											handleSelectedFile( e.dataTransfer.files?.[0] );
										} }

										onClick={ ( e ) => {
											e.preventDefault();
											e.stopPropagation();

											fileInput.current.click();
										} }
									>
										<Typography component="p">Click to select a <strong>JSON</strong> file</Typography>
										<Typography component="p" variant="caption" color="text.secondary">
											or drag and drop
										</Typography>
									</Button>
								) }

								<input
									ref={ fileInput }
									type="file"
									hidden={ true }
									accept="application/json"
									style={ { display: 'none' } }
									onChange={ ( e ) => {
										e.preventDefault();
										handleSelectedFile( e.target.files?.[0] );
									} }
								/>
							</Stack>
						</form>
					</DialogContent>

					<DialogActions>
						<Button type="button" onClick={ closeDialog }>Dismiss</Button>
						<SubmitButton
							form="scp-import-form"
							disabled={ ! Boolean( file ) }
						>Apply</SubmitButton>
					</DialogActions>
				</Dialog>
			) }
		</>
	);
}
