import { createContext, useContext, useCallback, useState } from 'react';
import { Snackbar, Alert } from '@mui/material';
import { generateId } from '../utils/generate-id';

const NotificationsCtx = createContext([]);

export function useNotifications() {
	const ctx = useContext(NotificationsCtx);
	if ( ! ctx ) {
		throw new Error('useNotifications must be used within NotificationsContext');
	}
	return ctx;
}

let counter = 0;

export function NotificationsContext( { children } ) {
	const [ messages, setMessages ] = useState([]);

	const addMessage = useCallback( ( { type, message: msgText, ...props } = {} ) => {
		const message = {
			...props,

			type,
			message: msgText,

			id: generateId( `msg-${ ++counter }` ),
		};

		setMessages( ( all ) => {
			return [
				message,
				...all,
			];
		} );
	}, [ setMessages ] );

	const removeMessage = useCallback( ( id ) => {
		setMessages( ( all ) => {
			return all.filter( ( msg ) => msg.id !== id );
		} );
	}, [ setMessages ] );

	const context = {
		messages,

		addMessage,
		removeMessage,
	};

	return (
		<NotificationsCtx.Provider value={ context }>
			{ children }
			<NotificationsList notifications={ messages } />
		</NotificationsCtx.Provider>
	);
}

function severity( message ) {
	switch ( message?.type ) {
		case 'success': return 'success';
		case 'info': return 'info';
		case 'warning': return 'warning';
		default: return undefined;
	};
}

function NotificationsList( { notifications }) {
	console.log( 'NotificationsList' );

	const { removeMessage } = useNotifications();

	const onClose = ( message ) => {
		removeMessage( message.id );
	};

	return (
		<>
			{ notifications.map( ( notification ) => {
				return (
					<Snackbar
						key={ notification.id }
						open
						autoHideDuration={ notification.duration || 1_500 }
						onClose={ () => onClose( notification ) }
						anchorOrigin={ {
							vertical: 'bottom',
							horizontal: 'right',
						} }
						sx={ {
							zIndex: 99999,
						} }
					>
						<Alert
							severity={ severity( notification ) }
							variant={ 'filled' }
							onClose={ () => onClose( notification ) }
						>{ notification.message }</Alert>
					</Snackbar>
				);
			} ) }
		</>
	);
}