import { useState, useEffect } from 'react';
import { ToggleButtonGroup } from '@mui/material';

import { FieldLabel, ToggleButton } from '../../components';

import { useSprintConfiguration } from '../../contexts/sprint-configuration';

export function UnitsPerDay() {
	console.log( 'Units' );

	const {
		sprintConfig,
		setPerDayMultiplier,
	} = useSprintConfiguration();

	const [ storyPointsPerDay, setStoryPointsPerDay ] = useState( () => sprintConfig.storyPointsPerDay );

	useEffect( () => {
		setPerDayMultiplier( storyPointsPerDay );
	}, [ storyPointsPerDay, setPerDayMultiplier ] );

	const spEnabled = 'story-points' === sprintConfig.units;

	return spEnabled && (
		<>
			<FieldLabel>Story-Points per Day:</FieldLabel>
			<ToggleButtonGroup
				value={ storyPointsPerDay }
				onChange={ ( _, value ) => value && setStoryPointsPerDay( value ) }
				exclusive
				variant="dark"
				color="primary"
				size="small"
				fullWidth
			>
				<ToggleButton value={ 1 }>1 SP</ToggleButton>
				<ToggleButton value={ 2 }>2 SP</ToggleButton>
				<ToggleButton value={ 4 }>4 SP</ToggleButton>
				<ToggleButton value={ 8 }>8 SP</ToggleButton>
			</ToggleButtonGroup>
		</>
	);
}
