import { FieldLabel, DatePicker } from '../../components';

import { useSprintConfiguration } from '../../contexts/sprint-configuration';

export function StartDate() {
	console.log( 'Start Date' );

	const {
		sprintConfig,
		setStartDate,
	} = useSprintConfiguration();

	return (
		<>
			<FieldLabel>Start date:</FieldLabel>
			<DatePicker
				value={ sprintConfig.startDate }
				onChange={ setStartDate }
			/>
		</>
	);
}
