import { useState, useEffect } from 'react';

import { ToggleButtonGroup } from '@mui/material';

import { FieldLabel, ToggleButton } from '../../components';

import { useSprintConfiguration } from '../../contexts/sprint-configuration';

export function Duration() {
	console.log( 'Duration' );

	const {
		sprintConfig,
		setDuration,
	} = useSprintConfiguration();

	const [ selectedDuration, setSelectedDuration ] = useState( () => {
		if ( sprintConfig.duration ) {
			return sprintConfig.duration;
		}
		return 14;
	} );

	useEffect( () => {
		setDuration( selectedDuration );
	}, [ selectedDuration, setDuration ] );

	return (
		<>
			<FieldLabel>Sprint Duration:</FieldLabel>
			<ToggleButtonGroup
				value={ selectedDuration }
				onChange={ ( _, newDuration ) => newDuration && setSelectedDuration( newDuration ) }
				exclusive
				color="primary"
				size="small"
				fullWidth
			>
				<ToggleButton value={ 7 }>1 week</ToggleButton>
				<ToggleButton value={ 14 }>2 weeks</ToggleButton>
				<ToggleButton value={ 21 }>3 weeks</ToggleButton>
				<ToggleButton value={ 28 }>4 weeks</ToggleButton>
			</ToggleButtonGroup>
		</>
	);
}
