import { Slider as MuiSlider } from '@mui/material';

const sx = {
	height: 4,

	'& .MuiSlider-thumb': {
		width: 14,
		height: 14,
	},

	'& .MuiSlider-track': {
		height: 4,
	},

	'& .MuiSlider-rail': {
		height: 4,
		opacity: 0.5,
	},

	'& .MuiSlider-markLabel': {
		fontSize: '0.7rem',
		opacity: 0.7,
	},
};

export function Slider( { sx: sxOverrides, ...props } ) {
	return (
		<MuiSlider
			sx={ {
				...sx,
				...sxOverrides,
			} }

			{ ...props }
		/>
	);
}
