import { Avatar as MuiAvatar } from '@mui/material';

import { muiStringAvatar } from '../utils/avatar';

export function Avatar( { member, sx, ...props } ) {
	const { sx: avatarSx, ...avatarProps } = muiStringAvatar( member );

	const muiAvatarSx = {
		...avatarSx,
		...sx,
	};

	const { onClick } = props;
	if ( 'function' === typeof onClick ) {
		muiAvatarSx.cursor = 'pointer';
	}

	const muiAvatarProps = {
		...avatarProps,
		...props,
	};

	return (
		<MuiAvatar sx={ muiAvatarSx } { ...muiAvatarProps } />
	);
}
