import {
	Typography,

	Stack,
	Box,

	Table,
	TableHead,
	TableBody,
	TableRow,
	TableCell,
} from '@mui/material';

import { Groups } from '@mui/icons-material';

import { Avatar } from '../../components/avatar';

import { useSprintConfiguration } from '../../contexts/sprint-configuration';
import { useTeamMembers } from '../../contexts/team-members';
import { useTeamCalendar } from '../../contexts/team-calendar';
import { useNotifications } from '../../contexts/notifications';

const weekDays = [ 'Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat' ];

const months = [
	'Jan', 'Feb', 'Mar', 'Apr', 'May', 'Jun',
	'Jul', 'Aug', 'Sep', 'Oct', 'Nov', 'Dec',
];

const schedules = {
	'mon-fri': 'Mon-Fri',
	'sun-thu': 'Sun-Thu',
};

const workScheduleWeekends = {
	'mon-fri': [ 'Sat', 'Sun' ],
	'sun-thu': [ 'Fri', 'Sat' ],
};

function dateLabelFor( date ) {
	const dateTime = new Date( date );
	const weekDay = weekDays[ dateTime.getDay() ];
	return `${ weekDay }, ${ months[ dateTime.getMonth() ] } ${ dateTime.getDate() }`;
}

function inferWeekends( teamMembers ) {
	let satSun = 0;
	let friSat = 0;

	teamMembers.forEach( ( member ) => {
		if ( 'mon-fri' === member.schedule ) {
			satSun++;
		}

		if ( 'sun-thu' === member.schedule ) {
			friSat++;
		}
	} );

	return ( satSun < friSat )
		? [ 'Fri', 'Sat' ]
		: [ 'Sat', 'Sun' ];
}

export function SprintCalendar() {
	console.log( 'Sprint Calendar' );

	const { addMessage } = useNotifications();

	const { calendar } = useSprintConfiguration();
	const { teamMembers } = useTeamMembers();
	const { holidays, toggleHoliday, daysOff, toggleDayOff } = useTeamCalendar();


	const weekEnd = inferWeekends( teamMembers );

	if ( ! teamMembers.length ) {
		return (
			<Stack alignItems="center" sx={ { p: 12 } }>
				<Groups sx={ { fontSize: '8rem', opacity: .20 } } />
				<Typography variant="body2">Right now the list of team members is empty.</Typography>
				<Typography variant="body2">Start by adding your first team member!</Typography>
			</Stack>
		);
	}

	return (
		<Box sx={ { overflowX: 'auto' } }>
			<Table className="tc-vars team-calendar">
				<TableHead>
					<TableRow key="th-main">
						<TableCell
							component="th"
							className="sticky"
							sx={ { backgroundColor: 'calendar.background' } }
						>Team Members</TableCell>

						{ calendar().map( ( date ) => {
							const label = dateLabelFor( date );

							const statusOf = ( theDate ) => {
								const day = new Date( theDate );
								const weekDay = weekDays[ day.getDay() ];

								if ( holidays.some( ( item ) => item.date === date ) ) {
									return 'holiday';
								}

								if ( -1 < weekEnd.indexOf( weekDay ) ) {
									return 'weekend';
								}

								return '';
							};

							const thProps = {
								className: statusOf( date ),
							};

							return (
								<TableCell
									component="th"
									key={ `th-${ date }` }
									onClick={ () => toggleHoliday( date ) }
									{ ...thProps }
								>
									{ label }
								</TableCell>
							);
						} ) }
					</TableRow>
				</TableHead>

				<TableBody>
					{ teamMembers.map( ( member ) => {
						if ( 'inactive' === member.status ) {
							return null;
						}

						return (
							<TableRow key={ `${ member.id }` }>
								<TableCell
									key={ `td-${ member.id }` }
									className="sticky"
									sx={ { backgroundColor: 'calendar.background' } }
								>
									<TeamMember member={ member } />
								</TableCell>
								{ calendar().map( ( date ) => {
									const statusOf = ( theDate, member = null ) => {
										const day = new Date( theDate );

										if ( -1 < workScheduleWeekends[ member.schedule ].indexOf( weekDays[ day.getDay() ] ) ) {
											return 'weekend';
										}

										if ( holidays.some( ( item ) => item.date === theDate ) ) {
											return 'holiday';
										}

										if ( daysOff.some( ( item ) => item.memberId === member.id && item.date === theDate ) ) {
											return 'day-off';
										}

										return 'open';
									}

									const tdProps = {
										className: statusOf( date, member ),
									};

									const handleDayOff = ( member, date ) => {
										addMessage( {
											type: 'info',
											message: <>
												{ dateLabelFor( date ) } for <strong>{ member.name }</strong>
											</>,
										} );

										toggleDayOff( member.id, date );
									};

									return (
										<TableCell
											key={ `td-${ member.id }-${ date }` }
											onClick={ () => { handleDayOff( member, date ) } }
											{ ...tdProps }
										>
											<span className="dot"></span>
										</TableCell>
									);
								} ) }
							</TableRow>
						);
					} ) }
				</TableBody>
			</Table>
		</Box>
	);
}

function TeamMember( { member } ) {
	console.log( 'TeamMember' );

	const { calendar } = useSprintConfiguration();
	const { toggleDayOff } = useTeamCalendar();

	const toggleAllDaysOff = ( memberId ) => {
		calendar().forEach( ( date ) => {
			toggleDayOff( memberId, date );
		} );
	};

	return (
		<Stack
			flexDirection="row"
			alignItems="center"
			justifyContent={ 'flex-start' }
			flexWrap={ false }
			gap={ 1 }
			sx={ { p: 1 } }
		>
			<Avatar
				member={ member }
				onClick={ () => toggleAllDaysOff( member.id ) }
			/>
			<Stack flexDirection="column">
				<Box sx={ { fontWeight: 600 } }>{ member.name }</Box>
				<Box sx={ { fontSize: '.7rem' } }>{ schedules[ member.schedule ] }</Box>
			</Stack>
		</Stack>
	);
}
