import { Typography, Stack } from '@mui/material';

export function SectionTitle( { children, icon: Icon, ...props } ) {
	return (
		<Stack
			flexDirection="row"
			gap={ 1.5 }
			alignItems="center"
			sx={ { p: 2 } }
			{ ...props }
		>
			{ Icon && <Icon className="section-icon" /> }
			{ children }
		</Stack>
	);
}

function TitleText( { children, ...props } ) {
	return (
		<Typography variant="h5" { ...props }>
			{ children }
		</Typography>
	);
}

SectionTitle.Title = TitleText;
