import { IconButton } from '@mui/material';
import { Close as CloseIcon } from '@mui/icons-material';

export function CloseIconButton( { sx: sxOverrides, ...props } ) {
	const sx = ( theme ) => ( {
		position: 'absolute',
		right: '12px',
		top: '12px',
		color: theme.palette.grey[500],

		...sxOverrides,
	} );

	return (
		<IconButton
			aria-label="close"
			sx={ sx }
			{ ...props }
		>
			<CloseIcon />
		</IconButton>
	);
}
