import { useState } from 'react';

import {
	Typography,

	Paper,
	Stack,
	Box,
	Divider,

	TextField,
	ToggleButtonGroup,
	Button,
	IconButton,
} from '@mui/material';

import {
	Groups as TeamMembersIcon,
	Delete as DeleteIcon,
	PeopleOutline,
	PersonAddAlt as AddTeamMemberIcon,
	PersonOutlineOutlined as ActiveIcon,
	PersonOffOutlined as InactiveIcon,
} from '@mui/icons-material';

import {
	Avatar,
	ToggleButton as BaseToggleButton,
} from '../../components';

import { SectionTitle } from '../section-title';

import { useTeamMembers } from '../../contexts/team-members';
import { useNotifications } from '../../contexts/notifications';

export function TeamManagement() {
	console.log( 'Team Management' );

	return (
		<Paper>
			<SectionTitle icon={ PeopleOutline }>
				<SectionTitle.Title>Team</SectionTitle.Title>
			</SectionTitle>
			<Divider />
			<MembersList />
			<Divider />
			<NewMember />
		</Paper>
	);
}


function NewMember() {
	const { addMessage } = useNotifications();

	const { addTeamMember } = useTeamMembers();

	const [ name, setName ] = useState( '' );
	const [ workSchedule, setWorkSchedule ] = useState( 'sun-thu' );

	const handleAdd = () => {
		addMessage( {
			type: 'success',
			duration: 3_000,
			message: <>
				New member <strong>{ name }</strong> was added to the team.
			</>,
		} );
		addTeamMember( name, workSchedule );
		setName('');
	};

	const handleSubmit = ( event ) => {
		event.preventDefault();
		event.stopPropagation();

		handleAdd();
	}

	const isNameEmpty = ! name.length;

	return (
		<form onSubmit={ handleSubmit }>
			<Stack flexDirection="row" gap={ 1.5 } alignItems="center" justifyContent="space-between" sx={ { p: 2 } }>
				<AddTeamMemberIcon />

				<Box flexGrow={ 1 }>
					<TextField
						fullWidth
						value={ name }
						placeholder='Name or Nickname'
						size="small"
						onChange={ ( e ) => setName( e.target.value ) }
					/>
				</Box>

				<ToggleButtonGroup
					exclusive
					size="small"
					color="warning"
					value={ workSchedule }
					disabled={ isNameEmpty }
					onChange={ ( _, newSchedule ) => newSchedule && setWorkSchedule( newSchedule ) }
				>
					<ToggleButton value="mon-fri">Mon-Fri</ToggleButton>
					<ToggleButton value="sun-thu">Sun-Thu</ToggleButton>
				</ToggleButtonGroup>

				<Button variant="contained" type="submit" disabled={ isNameEmpty }>Add Member</Button>
			</Stack>
		</form>
	);
}

function MembersList() {
	console.log('MembersList');

	const { addMessage } = useNotifications();

	const {
		teamMembers,
		removeTeamMember,
		updateWorkSchedule,
		toggleStatus,
	} = useTeamMembers();

	if ( ! teamMembers.length ) {
		return (
			<Stack alignItems="center" sx={ { p: 12 } }>
				<TeamMembersIcon sx={ { fontSize: '8rem', opacity: .20 } } />
				<Typography variant="body2">Right now the list of team members is empty.</Typography>
				<Typography variant="body2">Start by adding your first team member!</Typography>
			</Stack>
		);
	}

	const handleRemove = ( member ) => {
		addMessage( {
			type: 'warning',
			duration: 2_000,
			message: <>
				<strong>{ member.name }</strong> was removed from the team.
			</>,
		} );
		removeTeamMember( member.id );
	};

	return (
		<Stack gap={ 1.25 } sx={ { p: 2 } }>
			{ teamMembers.map( ( member ) => {
				const memberId = member.id;
				return (
					<MemberCard
						key={ memberId }
						member={ member }
						onToggleStatus={ () => toggleStatus( memberId ) }
						onChangeSchedule={ ( newSchedule ) => newSchedule && updateWorkSchedule( memberId, newSchedule ) }
						onRemove={ () => handleRemove( member ) }
					/>
				);
			} ) }
		</Stack>
	);
}

function MemberCard( { member, onRemove, onChangeSchedule, onToggleStatus } ) {
	return (
		<Paper variant="outlined" sx={ { px: 2, py: 1.5, borderRadius: 3 } }>
			<Stack flexDirection="row" gap={ 1.25 } alignItems="center" justifyContent="space-between">
				<Avatar member={ member } />

				<Box flexGrow={ 1 }>{ member.name }</Box>

				<IconButton onClick={ () => onToggleStatus() }>
					<MemberStatusIcon status={ member.status } />
				</IconButton>

				<ToggleButtonGroup
					value={ member.schedule }
					onChange={ ( _, newSchedule ) => newSchedule && onChangeSchedule( newSchedule ) }
					exclusive
					color="warning"
					size="small"
				>
					<ToggleButton value="mon-fri">Mon-Fri</ToggleButton>
					<ToggleButton value="sun-thu">Sun-Thu</ToggleButton>
				</ToggleButtonGroup>

				<DeleteIconButton disabled={ ! onRemove } onClick={ () => onRemove() }>
					<DeleteIcon />
				</DeleteIconButton>
			</Stack>
		</Paper>
	);
}

function MemberStatusIcon( { status } ) {
	if ( 'inactive' === status ) {
		return <InactiveIcon sx={ { color: 'silver' } } />
	}
	return <ActiveIcon sx={ { color: 'green' } } />
}

function DeleteIconButton( { children, sx, ...props } ) {
	const iconButtonSx = {
		color: 'silver',
		"&:hover": {
			color: 'rgba(255, 0, 0, .75)',
		},

		...sx,
	};

	return (
		<IconButton sx={ iconButtonSx } { ...props }>
			{ children }
		</IconButton>
	);
}

function ToggleButton( { children, sx, ...props } ) {
	const toggleButtonSx = {
		textTransform: 'lowercase',
		px: 2,

		...sx,
	};

	return (
		<BaseToggleButton sx={ toggleButtonSx } { ...props }>
			{ children }
		</BaseToggleButton>
	);
}
