import { createContext, useContext, useCallback, useEffect } from 'react';
import { readJson } from '../utils';
import { useLocalStorage } from '../hooks/use-local-storage';

import { SCP } from '../constants';

const TeamCalendarCtx = createContext( undefined );

export function useTeamCalendar() {
	const ctx = useContext( TeamCalendarCtx );
	if ( ! ctx ) {
		throw new Error('useTeamCalendar hook must be used within TeamCalendarContext');
	}
	return ctx;
}

export function TeamCalendarContext( { children } ) {
	const [ holidays, setHolidays ] = useLocalStorage( SCP.storage.holidays, [] );
	const [ daysOff, setDaysOff ] = useLocalStorage( SCP.storage.daysOff, [] );

	useEffect( () => {
		function reload() {
			setHolidays( readJson( SCP.storage.holidays, [] ) );
			setDaysOff( readJson( SCP.storage.daysOff, [] ));
		}
		window.addEventListener( SCP.events.storage.reload, reload );
		return () => {
			window.removeEventListener( SCP.events.storage.reload, reload );
		};
	}, [ setHolidays, setDaysOff ] );

	const toggleHoliday = useCallback( ( date ) => {
		setHolidays( ( calendar ) => {
			const dateExists = calendar.some( ( item ) => {
				return item.date === date;
			} );

			if ( ! dateExists ) {
				const newHoliday = {
					date: date,
				};

				return [
					...calendar,
					newHoliday,
				];
			}

			return calendar.filter( ( item ) => {
				return item.date !== date;
			} );
		} );
	}, [ setHolidays ] );

	const toggleDayOff = useCallback( ( teamMemberId, date ) => {
		setDaysOff( ( calendar ) => {
			const dateExists = calendar.some( ( item ) => {
				return item.date === date && item.memberId === teamMemberId;
			} );

			if ( ! dateExists ) {
				const newDayOff = {
					date: date,
					memberId: teamMemberId,
				};

				return [
					...calendar,
					newDayOff,
				];
			}

			return calendar.filter( ( item ) => {
				return item.date !== date || item.memberId !== teamMemberId;
			} );
		} );
	}, [ setDaysOff ] );

	const context = {
		holidays,
		toggleHoliday,

		daysOff,
		toggleDayOff,
	};

	return (
		<TeamCalendarCtx.Provider value={ context }>
			{ children }
		</TeamCalendarCtx.Provider>
	);
}
