export function formatDate( date, options = {} ) {
	const { glue = '-' } = options;

	const yyyy = date.getFullYear();
	const mm = date.getMonth() + 1;
	const dd = date.getDate();

	return [
		yyyy,
		String( mm ).length < 2 ? [ '0', mm ].join('') : mm,
		String( dd ).length < 2 ? [ '0', dd ].join('') : dd,
	].join( glue );
}

export function formatTime( date, options = {} ) {
	const { glue = ':' } = options;

	const hh = date.getHours();
	const mm = date.getMinutes();
	const ss = date.getSeconds();

	return [
		String( hh ).length < 2 ? [ '0', hh ].join('') : hh,
		String( mm ).length < 2 ? [ '0', mm ].join('') : mm,
		String( ss ).length < 2 ? [ '0', ss ].join('') : ss,
	].join( glue );
}

export function formatDateTime( date, options = {} ) {
	const {
		glue = ' ',
		dateGlue = '-',
		timeGlue = ':',
	} = options;

	return [
		formatDate( date, dateGlue ),
		formatTime( date, timeGlue ),
	].join( glue );
}
